// Check Priority
// If type == '', then return data;
// If type == 'ITEM', then return the data with the priority order which is Org + User + Customer ID > Org + User > Org + Customer ID > Org
// If type == 'CUSTOMER', then return the data with the priority order which is Org + User > Org

// Function to calculate priority weight
function getPriorityWeight(item, type) {
  const orgLevel = item.apply_to_user === 0 ;
  const userLevel = item.update_user === userID && item.apply_to_user === 1;
  const hasCustomer = !!item.customer_id;

  if (type === 'ITEM') {
    if (userLevel && hasCustomer) return 4;
    if (userLevel) return 3;
    if (orgLevel && hasCustomer) return 2;
    if (orgLevel) return 1;
    return 0;
  } else if (type === 'CUSTOMER') {
    if (userLevel) return 2;
    if (orgLevel) return 1;
    return 0;
  }
  return 0;
}

if (data.length > 0) {
  if (type === '') {
    status = 'Success';
  } else if (type === 'ITEM' || type === 'CUSTOMER') {
    // Add weight to each record
    data = data.map(item => ({
      ...item,
      priorityWeight: getPriorityWeight(item, type)
    }));

    // Sort by weight (highest first)
    data.sort((a, b) => b.priorityWeight - a.priorityWeight);

    status = 'Success';
  } else {
    status = 'Success';
